// verify-lida-visual-audit.mjs
// Verifies the per-measure Lida Rose visual audit pack generated by
// build-lida-visual-audit.mjs.
import fs from 'fs';
import path from 'path';
import {
  EXPECTED_LEAD_NOTE_COUNT,
  PRINTED_LEAD_AUDIT_MEASURES,
} from './lida-lead-printed-manifest.mjs';
import {
  EXPECTED_BARITONE_NOTE_COUNT,
  PRINTED_BARITONE_AUDIT_MEASURES,
} from './lida-baritone-printed-manifest.mjs';

const OUT = path.resolve(process.env.LIDA_VISUAL_AUDIT_OUT || 'C:/Users/jonch/Projects/jarvis/data/vocal-trainer/runtime-logs/lida-visual-audit');
const manifestPath = path.join(OUT, 'manifest.json');
const errors = [];

assert(fs.existsSync(manifestPath), `missing visual audit manifest: ${manifestPath}`);
const manifest = JSON.parse(fs.readFileSync(manifestPath, 'utf8'));

const EXPECTED = {
  Lead: {
    measures: 35,
    notes: EXPECTED_LEAD_NOTE_COUNT,
    auditMeasures: PRINTED_LEAD_AUDIT_MEASURES.map((m) => m.measure),
  },
  Baritone: {
    measures: 31,
    notes: EXPECTED_BARITONE_NOTE_COUNT,
    auditMeasures: PRINTED_BARITONE_AUDIT_MEASURES.map((m) => m.measure),
  },
};

assert(manifest.version === 'lida-visual-audit-v1', `unexpected manifest version ${manifest.version}`);
assert(Array.isArray(manifest.entries), 'manifest entries missing');

for (const [part, expected] of Object.entries(EXPECTED)) {
  const entries = manifest.entries.filter((e) => e.part === part);
  const measures = entries.map((e) => e.measure);
  const noteCount = entries.reduce((sum, e) => sum + (e.pitched?.length || 0), 0);
  assert(entries.length === expected.measures, `${part}: expected ${expected.measures} measure crops, got ${entries.length}`);
  assert(noteCount === expected.notes, `${part}: expected ${expected.notes} notes, got ${noteCount}`);
  assert(isConsecutive(measures), `${part}: measure crops are not consecutive: ${measures.join(',')}`);
  for (const measure of expected.auditMeasures) {
    const entry = entries.find((e) => e.measure === measure);
    assert(entry, `${part}: missing crop for printed audit measure ${measure}`);
    assert(entry?.auditMeasure === true, `${part} m${measure}: not flagged as printed audit measure`);
  }
}

let blankish = 0;
let clamped = 0;
for (const entry of manifest.entries) {
  assert(fs.existsSync(entry.cropPath), `${entry.part} m${entry.measure}: missing crop ${entry.cropPath}`);
  assert(entry.stats?.width > 80 && entry.stats?.height > 50,
    `${entry.part} m${entry.measure}: crop too small ${entry.stats?.width}x${entry.stats?.height}`);
  if ((entry.stats?.stdev ?? 0) < 12 || (entry.stats?.darkRatio ?? 0) < 0.01) {
    blankish++;
    errors.push(`${entry.part} m${entry.measure}: crop looks too blank stdev=${entry.stats?.stdev} dark=${entry.stats?.darkRatio}`);
  }
  if (entry.clamped) clamped++;
}

assert(fs.existsSync(path.join(OUT, 'index.html')), 'missing visual audit index.html');
assert(manifest.checks?.every((check) => check.status === 'pass'),
  `manifest contains failed checks: ${JSON.stringify(manifest.checks)}`);

if (errors.length) {
  console.error('LIDA VISUAL AUDIT FAILED:\n  ' + errors.join('\n  '));
  process.exit(1);
}

console.log('Lida visual audit PASS');
console.log(`manifest: ${manifestPath}`);
console.log(`crops: ${manifest.entries.length}; clamped=${clamped}; blankish=${blankish}`);

function isConsecutive(values) {
  return values.every((value, index) => value === index + 1);
}

function assert(condition, message) {
  if (!condition) errors.push(message);
}
